SELECT *
     FROM (
         SELECT ROWNUM AS RNUM, T1.*
         FROM (
             SELECT *
             FROM ORDERS
             WHERE ORDER_DATE >= #{startDate}
               AND ORDER_DATE < #{nextMonthStartDate}
             ORDER BY ORDER_DATE DESC
         ) T1
     )
     WHERE RNUM BETWEEN #{offset} AND #{limit}

	  SELECT COUNT(*)
        FROM ORDERS
        WHERE ORDER_DATE >= #{startDate}
          AND ORDER_DATE < #{nextMonthStartDate}

SELECT NVL(SUM(ORDER_TOTAL_PRICE), 0)
       FROM ORDERS
       WHERE ORDER_DATE >= #{startDate}
         AND ORDER_DATE < #{nextMonthStartDate}

SELECT COUNT(*)
      FROM ORDERS
      WHERE ORDER_DATE >= #{startDate}
        AND ORDER_DATE < #{nextMonthStartDate}

